const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeBookCovers = async (files: File[]): Promise<Book[]> => {
  // Always create a new instance to pick up the most recent key from the environment
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare image parts
  const imageParts = await Promise.all(
    files.map(async (file) => ({
      inlineData: {
        data: await fileToBase64(file),
        mimeType: file.type,
      },
    }))
  );

  const prompt = `
    Analiza las siguientes imágenes de portadas de libros.
    Para cada imagen, identifica el TÍTULO del libro y el AUTOR.

    Reglas:
    1. Si el texto es claro en la imagen, úsalo directamente.
    2. Si el texto es borroso, oscuro o difícil de leer, usa tus herramientas de búsqueda (Google Search) para encontrar la coincidencia más probable basada en los elementos visuales visibles.
    3. Devuelve una lista JSON estricta.
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        title: {
          type: Type.STRING,
          description: "El título completo del libro identificado",
        },
        author: {
          type: Type.STRING,
          description: "El nombre del autor o autores del libro",
        },
      },
      required: ["title", "author"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', 
      contents: {
        parts: [
          ...imageParts,
          { text: prompt }
        ]
      },
      config: {
        thinkingConfig: { thinkingBudget: 24576 }, 
        tools: [{ googleSearch: {} }],
        responseMimeType: 'application/json',
        responseSchema: responseSchema,
      }
    });

    const textResponse = response.text;
    if (!textResponse) {
      throw new Error("No se recibió respuesta de la IA");
    }

    return JSON.parse(textResponse);

  } catch (error: any) {
    console.error("Error analyzing books:", error);
    // Propagate common permission errors with specific guidance
    if (error.message?.includes("403") || error.message?.includes("permission")) {
      throw new Error("Error de permisos (403). Por favor, asegúrate de haber seleccionado una API Key vinculada a un proyecto con facturación habilitada.");
    }
    throw error;
  }
};
