// Use GoogleGenAI from @google/genai as required
import { GoogleGenAI } from "@google/genai";
import { Book } from "../types";

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeBookCovers = async (files: File[]): Promise<Book[]> => {
  // Always create a new instance right before making an API call to pick up the most recent key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Prepare image parts for the multimodal request
  const imageParts = await Promise.all(
    files.map(async (file) => ({
      inlineData: {
        data: await fileToBase64(file),
        mimeType: file.type,
      },
    }))
  );

  /**
   * Guidance: When using googleSearch, the response.text might not be valid JSON.
   * We will use a clear text-based format and parse it manually.
   */
  const prompt = `
    Analiza las siguientes imágenes de portadas de libros.
    Para cada imagen, identifica el TÍTULO del libro y el AUTOR.
    Si el texto es borroso, oscuro o difícil de leer, usa tus herramientas de búsqueda (Google Search) para encontrar la coincidencia más probable.
    Responde ÚNICAMENTE con una lista en el siguiente formato, una línea por libro:
    TITULO: [título completo] | AUTOR: [nombre del autor]
  `;

  try {
    /**
     * Using gemini-3-pro-image-preview as it is required when requesting real-time 
     * information with the googleSearch tool in a multimodal (image) context.
     */
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview', 
      contents: {
        parts: [
          ...imageParts,
          { text: prompt }
        ]
      },
      config: {
        // Only googleSearch is permitted when using grounding. Do not use other tools.
        tools: [{ googleSearch: {} }],
        // Avoid responseMimeType: 'application/json' as search grounding citations can break JSON format.
        thinkingConfig: { thinkingBudget: 32768 }, 
      }
    });

    const textResponse = response.text;
    if (!textResponse) {
      throw new Error("No se recibió respuesta de la IA");
    }

    // ALWAYS extract website URLs from groundingChunks when using Google Search.
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks
      ?.map((chunk: any) => chunk.web)
      .filter(Boolean)
      .map((web: any) => ({
        uri: web.uri,
        title: web.title || 'Referencia de búsqueda'
      })) || [];

    // Parse the text-based response manually to avoid JSON parsing errors with grounded text.
    const books: Book[] = textResponse
      .split('\n')
      .map(line => line.trim())
      .filter(line => line.includes('|') && line.toUpperCase().includes('TITULO:'))
      .map(line => {
        const parts = line.split('|');
        const title = parts[0].replace(/TITULO:/i, '').trim();
        const author = parts[1].replace(/AUTOR:/i, '').trim();
        return {
          title,
          author,
          sources
        };
      });

    return books;

  } catch (error: any) {
    console.error("Error analyzing books:", error);
    if (error.message?.includes("403") || error.message?.includes("permission")) {
      throw new Error("Error de permisos (403). Por favor, asegúrate de haber seleccionado una API Key vinculada a un proyecto con facturación habilitada.");
    }
    throw error;
  }
};
