import React, { useState, useCallback, useEffect } from 'react';
import { Loader2, Sparkles, AlertCircle, Key, ExternalLink, BookOpen } from 'lucide-react';
import Header from './components/Header';
import ImageUploader from './components/ImageUploader';
import ResultsList from './components/ResultsList';
import { analyzeBookCovers } from './services/geminiService';
import { AnalyzedImage, Book, AppStatus } from './types';

// Properly declare global types to match the environment's expected interface and avoid modifier errors
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    readonly aistudio: AIStudio;
  }
}

function App() {
  const [images, setImages] = useState<AnalyzedImage[]>([]);
  const [books, setBooks] = useState<Book[]>([]);
  const [status, setStatus] = useState<AppStatus>('idle');
  const [error, setError] = useState<string | null>(null);
  const [hasKey, setHasKey] = useState<boolean | null>(null);

  useEffect(() => {
    const checkKey = async () => {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasKey(selected);
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    await window.aistudio.openSelectKey();
    // Proceed assuming success to handle potential race conditions as per instructions
    setHasKey(true);
  };

  const handleImagesSelected = useCallback((files: File[]) => {
    const newImages: AnalyzedImage[] = files.map(file => ({
      id: crypto.randomUUID(),
      file,
      previewUrl: URL.createObjectURL(file)
    }));

    setImages(prev => [...prev, ...newImages]);
    if (status === 'success') {
      setStatus('idle');
      setBooks([]);
    }
  }, [status]);

  const handleRemoveImage = useCallback((id: string) => {
    setImages(prev => {
      const newImages = prev.filter(img => img.id !== id);
      const removed = prev.find(img => img.id === id);
      if (removed) URL.revokeObjectURL(removed.previewUrl);
      return newImages;
    });
  }, []);

  const handleAnalyze = async () => {
    if (images.length === 0) return;

    setStatus('analyzing');
    setError(null);
    setBooks([]);

    try {
      const files = images.map(img => img.file);
      const results = await analyzeBookCovers(files);
      setBooks(results);
      setStatus('success');
    } catch (err: any) {
      console.error(err);
      const msg = err.message || "Ocurrió un error inesperado.";
      setError(msg);
      setStatus('error');

      /**
       * If the request fails with permission errors or missing entities, 
       * reset the key selection state to prompt the user to select a key again.
       */
      if (
        msg.toLowerCase().includes("permission") || 
        msg.toLowerCase().includes("403") ||
        msg.includes("Requested entity was not found")
      ) {
        setHasKey(false);
      }
    }
  };

  if (hasKey === false) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-xl border border-slate-200 p-8 text-center">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl">
              <BookOpen className="w-12 h-12" />
            </div>
          </div>
          <h1 className="text-2xl font-bold text-slate-900 mb-2">Configuración Requerida</h1>
          <p className="text-slate-600 mb-8">
            Para utilizar las funciones avanzadas de identificación de libros, necesitas seleccionar una API Key de un proyecto de Google Cloud con facturación habilitada.
          </p>

          <div className="space-y-4">
            <button
              onClick={handleSelectKey}
              className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold transition-all shadow-lg flex items-center justify-center gap-2"
            >
              <Key className="w-5 h-5" />
              Configurar API Key
            </button>

            <a 
              href="https://ai.google.dev/gemini-api/docs/billing" 
              target="_blank" 
              rel="noopener noreferrer"
              className="flex items-center justify-center gap-1.5 text-sm text-slate-500 hover:text-indigo-600 transition-colors"
            >
              Documentación sobre facturación <ExternalLink className="w-3.5 h-3.5" />
            </a>
          </div>
        </div>
      </div>
    );
  }

  if (hasKey === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-indigo-600 animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-1 max-w-4xl w-full mx-auto px-4 py-8 pb-32">
        <div className="space-y-8">

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8">
            <div className="mb-6">
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sube tus fotos</h2>
              <p className="text-slate-600">
                Selecciona fotos de las portadas. La IA identificará los títulos y autores automáticamente utilizando búsqueda avanzada.
              </p>
            </div>

            <ImageUploader 
              images={images}
              onImagesSelected={handleImagesSelected}
              onRemoveImage={handleRemoveImage}
              disabled={status === 'analyzing'}
            />
          </div>

          {error && (
            <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3 text-red-700 animate-in fade-in slide-in-from-top-2">
              <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
              <div>
                <p className="font-semibold">Error de Análisis</p>
                <p className="text-sm opacity-90">{error}</p>
              </div>
            </div>
          )}

          <ResultsList books={books} />

        </div>
      </main>

      {/* Sticky Action Bar */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-white/80 backdrop-blur-md border-t border-slate-200 z-40">
        <div className="max-w-4xl mx-auto flex items-center justify-between gap-4">
          <div className="text-sm text-slate-500 hidden sm:block">
            {images.length === 0 
              ? "Sube imágenes para comenzar" 
              : `${images.length} imagen${images.length !== 1 ? 'es' : ''} seleccionada${images.length !== 1 ? 's' : ''}`
            }
          </div>

          <button
            onClick={handleAnalyze}
            disabled={images.length === 0 || status === 'analyzing'}
            className={`
              flex-1 sm:flex-none sm:w-auto px-8 py-3 rounded-lg font-semibold text-white shadow-lg transition-all duration-200 flex items-center justify-center gap-2
              ${images.length === 0 || status === 'analyzing'
                ? 'bg-slate-400 cursor-not-allowed shadow-none' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-500/25 active:scale-[0.98]'
              }
            `}
          >
            {status === 'analyzing' ? (
              <>
                <Loader2 className="w-5 h-5 animate-spin" />
                <span>Identificando libros...</span>
              </>
            ) : (
              <>
                <Sparkles className="w-5 h-5" />
                <span>Analizar Libros</span>
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

export default App;
